Let's start by implementing the basic structure of your event sourcing system.

### Step 1: Define the `EventStore` class

This class will handle appending events to the store with optimistic concurrency checking, loading the store, and managing the stream version.

```python
# eventsource.py

class EventStore:
    def __init__(self):
        self.events = []

    def append(self, event, expected_version=None):
        if expected_version is not None and len(self.events) != expected_version:
            raise VersionMismatchError(f"Expected {expected_version} events, got {len(self.events)}")
        self.events.append(event)
        return len(self.events) - 1

    def load(self):
        return self.events
```

### Step 2: Define the `Event` class

This class will represent individual events.

```python
# eventsource.py

class Event:
    def __init__(self, type, payload):
        self.type = type
        self.payload = payload

    def __repr__(self):
        return f"Event(type={self.type}, payload={self.payload})"

# Define specific events for the bank account example
class AccountOpened(Event):
    pass

class Deposited(Event):
    pass

class Withdrawn(Event):
    pass

class AccountClosed(Event):
    pass
```

### Step 3: Define the `Projection` base class

This class will serve as a base for projections that rebuild their state from the event stream.

```python
# eventsource.py

class Projection:
    def __init__(self, events=[]):
        self.events = events
        self.state = {}

    @property
    def stream_version(self):
        return len(self.events)

    @stream_version.setter
    def stream_version(self, value):
        raise AttributeError("Stream version cannot be set directly")

    def rebuild(self):
        for event in self.events:
            if hasattr(self, f"_handle_{event.type}"):
                getattr(self, f"_handle_{event.type}")(event.payload)
```

### Step 4: Define the `BankAccount` projection

This class will handle all the specific events related to bank accounts.

```python
# eventsource.py

class BankAccount(Projection):
    def __init__(self, account_id):
        super().__init__()
        self.account_id = account_id

    def _handle_AccountOpened(self, payload):
        assert not self.state.get('account_id'), "Account already opened."
        self.state['account_id'] = payload['account_id']
        self.state['balance'] = 0

    def _handle_Deposited(self, payload):
        assert self.state.get('account_id'), "Account not opened."
        self.state['balance'] += payload['amount']

    def _handle_Withdrawn(self, payload):
        assert self.state.get('account_id'), "Account not opened."
        assert self.state['balance'] >= payload['amount'], "Insufficient balance."
        self.state['balance'] -= payload['amount']

    def _handle_AccountClosed(self, payload):
        assert self.state.get('account_id'), "Account not opened."
        del self.state['account_id']
        del self.state['balance']
```

### Step 5: Define the `VersionMismatchError`
This error will be raised when an expected version does not match the actual length of the event stream.

```python
# eventsource.py

class VersionMismatchError(Exception):
    pass
```

You can now start implementing your tests for this basic structure. The above code provides the core components to implement event sourcing with optimistic concurrency handling and projections.
